render(() => {
    const [value, setValue] = React.useState(() => new Date().setMonth(1));
    const [visible, setVisible] = React.useState(true);

    const calendarStyles = {
        border: '1px solid rgba(233, 233, 235, 1)',
        borderRadius: 'var(--calendar-popover-border-radius, var(--border-radius-16))',
        boxSizing: 'border-box',
        boxShadow: 'var(--shadow-m)',
    };

    return (
        <>
            <div style={{ width: '344px', ...calendarStyles }}>
                <CalendarWithSkeleton
                    value={value}
                    onChange={setValue}
                    calendarVisible={visible}
                    selectorView='month-only'
                    responsive={true}
                    showCurrentYearSelector={true}
                />
            </div>
            <div style={{ marginTop: '32px' }}></div>
            <Button size={40} onClick={() => setVisible(!visible)}>
                Показать скелетон
            </Button>
        </>
    );
});

render(() => {
    const [open, setOpen] = React.useState(false);
    const [value, setValue] = React.useState();

    const [firstRadioValue, setFirstRadioValue] = React.useState('rounded');

    React.useEffect(() => {
        setValue();
    }, [firstRadioValue]);

    const onFirstRadioChange = React.useCallback((_, payload) => {
        setFirstRadioValue(payload.value);
    }, []);

    return (
        <Container>
            <Button block={true} onClick={() => setOpen(true)}>
                Открыть календарь
            </Button>
            <CalendarMobile
                mode={'range'}
                selectorView={'month-only'}
                shape={firstRadioValue}
                clickableMonth={true}
                value={value}
                onChange={(dateFrom, dateTo) => setValue({ dateFrom, dateTo })}
                onClose={() => setOpen(false)}
                open={open}
            />
            <div style={{ marginTop: '32px' }}>
                <RadioGroup
                    label='Форма'
                    direction='vertical'
                    name='radioGroup'
                    onChange={onFirstRadioChange}
                    value={firstRadioValue}
                >
                    <Radio size={24} label='Круглая' value='rounded' />
                    <Radio size={24} label='Прямоугольная' value='rectangular' />
                </RadioGroup>
            </div>
        </Container>
    );
});

render(() => {
    const [values, setValues] = React.useState({
        value: new Date(),
        valueFrom: new Date(),
        valueTo: new Date(),
    });

    const handler = (event, newValues) => setValues(newValues);

    return (
        <div style={{ width: 500 }}>
            <p style={{ margin: 0 }}>Дата начала: {format(values.valueFrom, DATE_FORMAT)}</p>
            <p style={{ marginTop: 10, marginBottom: 20 }}>
                Дата конца: {format(values.valueTo, DATE_FORMAT)}
            </p>

            <PeriodSlider
                value={values.value}
                periodType='year'
                onPrevArrowClick={handler}
                onNextArrowClick={handler}
            />

            <br />

            <PeriodSlider
                value={values.value}
                periodType='quarter'
                onPrevArrowClick={handler}
                onNextArrowClick={handler}
            />

            <br />

            <PeriodSlider
                value={values.value}
                periodType='month'
                onPrevArrowClick={handler}
                onNextArrowClick={handler}
            />

            <br />

            <PeriodSlider
                value={values.value}
                periodType='month'
                onPrevArrowClick={handler}
                onNextArrowClick={handler}
                showCurrentYearSelector={true}
            />

            <br />

            <PeriodSlider
                value={values.value}
                periodType='day'
                onPrevArrowClick={handler}
                onNextArrowClick={handler}
            />

            <br />

            <PeriodSlider periodType='day' onPrevArrowClick={handler} onNextArrowClick={handler} />
        </div>
    );
});
